const sprint = $('Get Jira Active Sprints').item.json;
const issues = $input.all().map(i => i.json);
const workspaceId = $('Split By Workspace').item.json.id;

const STATUS_MAP = {
  'To Do': 'todo',
  'In Progress': 'in_progress',
  'Blocked': 'blocked',
  'Done': 'done',
  'Cancelled': 'cancelled'
};

function normaliseStatus(statusCategory) {
  if (statusCategory === 'To Do' || statusCategory === 'new') return 'todo';
  if (statusCategory === 'In Progress' || statusCategory === 'indeterminate') return 'in_progress';
  if (statusCategory === 'Done' || statusCategory === 'complete') return 'done';
  return 'in_progress';
}

const normalised = issues.map(issue => ({
  id: issue.id,
  key: issue.key,
  summary: issue.fields.summary,
  status: normaliseStatus(issue.fields.status?.statusCategory?.key),
  assignee: issue.fields.assignee?.displayName ?? null,
  story_points: issue.fields.story_points ?? issue.fields.customfield_10016 ?? null,
  updated_at: issue.fields.updated,
  blocked_days: issue.fields.status?.name?.toLowerCase() === 'blocked'
    ? Math.floor((Date.now() - new Date(issue.fields.updated).getTime()) / 86400000)
    : 0,
  labels: issue.fields.labels ?? [],
  priority: issue.fields.priority?.name ?? null
}));

const completed = normalised.filter(i => i.status === 'done');
const inProgress = normalised.filter(i => i.status === 'in_progress');
const blocked = normalised.filter(i => i.status === 'blocked');

const totalSP = normalised.reduce((s, i) => s + (i.story_points ?? 0), 0);
const completedSP = completed.reduce((s, i) => s + (i.story_points ?? 0), 0);
const burndown = totalSP > 0 ? Math.round((completedSP / totalSP) * 10000) / 100 : 0;

return {
  sprint_id: String(sprint.id),
  sprint_name: sprint.name,
  board_id: String(sprint.originBoardId),
  workspace_id: workspaceId,
  start_date: new Date(sprint.startDate).toISOString(),
  end_date: new Date(sprint.endDate).toISOString(),
  state: sprint.state,
  total_story_points: totalSP,
  completed_story_points: completedSP,
  burndown_percent: burndown,
  tickets_completed: completed,
  tickets_in_progress: inProgress,
  tickets_blocked: blocked,
  synced_at: new Date().toISOString()
};

